import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { addSensor } from "../api/sensorsapi";
import { getActiveSensors } from "../api/activeapi";
import ConnectionModal from "../components/ConnectionModal";

const Sensor = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [sensors, setSensors] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [showConnectionModal, setShowConnectionModal] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");
  const [editSensor, setEditSensor] = useState(null);

  const [form, setForm] = useState({
    sensorName: "",
    location: "",
    topicName: "",
    quantity: "",
    unit: "",
  });

  const [errors, setErrors] = useState({});

  const connectionId = Number(localStorage.getItem("sb_connectionId")) || 0;

  // ✅ fetch sensors (no active/inactive)
  const fetchSensors = async () => {
    if (!connectionId) return;
    const data = await getActiveSensors(connectionId);
    if (Array.isArray(data)) setSensors(data);
  };

  useEffect(() => {
    if (location.state?.showSuccess) {
      setSuccessMsg("Connected successfully!");
      setTimeout(() => setSuccessMsg(""), 3000);
    }
    fetchSensors();
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
  };

  const handleAddSensor = async () => {
    await addSensor({
      connectionId,
      sensorName: form.sensorName,
      location: form.location,
      topicName: form.topicName,
      quantity: form.quantity,
      unit: form.unit,
    });
    setShowForm(false);
    fetchSensors();
  };

  return (
    <div>
      {/* HEADER */}
      <div className="sb-page-header px-4 py-3 mb-4">
        <h5 className="sb-header-title mb-1">
          <i className="bi bi-broadcast me-2 sb-accent"></i>Sensors
        </h5>
        <p className="sb-header-subtitle mb-0">
          Manage and monitor your sensors.
        </p>
      </div>

      {successMsg && (
        <div className="position-fixed top-0 end-0 m-4">
          <div className="alert alert-success shadow">{successMsg}</div>
        </div>
      )}

      {/* TOOLBAR */}
      <div className="container-fluid px-4 mb-4 d-flex justify-content-end gap-2">
        <button
          className="btn sb-connect-btn d-flex align-items-center gap-2"
          onClick={() => setShowConnectionModal(true)}
        >
          <i className="bi bi-hdd-network"></i>
          Add Connection
        </button>

        {/* ✅ OLD ADD SENSOR BUTTON */}
        <button
          className="btn sb-connect-btn d-flex align-items-center gap-2"
          onClick={() => {
            setEditSensor(null);
            setForm({
              sensorName: "",
              location: "",
              topicName: "",
              quantity: "",
              unit: "",
            });
            setErrors({});
            setShowForm(true);
          }}
        >
          <i className="bi bi-plus-circle-fill"></i>
          Add Sensor
        </button>
      </div>

      {/* SENSOR CARDS (OLD UI) */}
      <div className="container-fluid px-4">
        <div className="row g-3">
          {sensors.map((sensor) => (
            <div
              key={sensor.sensorId}
              className="col-12 col-md-6 col-lg-4"
            >
              <div
                className="card border-0 shadow-sm p-3"
                style={{ borderRadius: "12px" }}
              >
                <h6 className="mb-1">{sensor.sensorName}</h6>
                <small className="text-muted">{sensor.topicName}</small>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* ✅ CONNECTION MODAL */}
      {showConnectionModal && (
        <ConnectionModal
          onClose={() => setShowConnectionModal(false)}
          sensors={sensors}
        />
      )}

      {/* ✅ OLD ADD SENSOR MODAL (UNCHANGED UI) */}
      {showForm && (
        <div
          className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center"
          style={{ backgroundColor: "rgba(0,0,0,0.5)", zIndex: 1050 }}
        >
          <div
            className="card border-0 shadow-lg p-4"
            style={{ width: "100%", maxWidth: "500px", borderRadius: "20px" }}
          >
            <div className="d-flex justify-content-between mb-4">
              <h5>Add New Sensor</h5>
              <button className="btn-close" onClick={() => setShowForm(false)} />
            </div>

            <input
              className="form-control mb-2"
              name="sensorName"
              placeholder="Sensor Name"
              value={form.sensorName}
              onChange={handleChange}
            />
            <input
              className="form-control mb-2"
              name="location"
              placeholder="Location"
              value={form.location}
              onChange={handleChange}
            />
            <input
              className="form-control mb-2"
              name="topicName"
              placeholder="Topic Name"
              value={form.topicName}
              onChange={handleChange}
            />
            <input
              className="form-control mb-2"
              name="quantity"
              placeholder="Quantity"
              value={form.quantity}
              onChange={handleChange}
            />
            <input
              className="form-control mb-3"
              name="unit"
              placeholder="Unit"
              value={form.unit}
              onChange={handleChange}
            />

            <div className="d-flex justify-content-end gap-2">
              <button
                className="btn btn-secondary"
                onClick={() => setShowForm(false)}
              >
                Cancel
              </button>
              <button
                className="btn sb-connect-btn"
                onClick={handleAddSensor}
              >
                Add Sensor
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sensor;
